        "sections": sections,
    }


def build_messages(item: Dict[str, Any]) -> List[Dict[str, str]]:
    context = item.get("context", "")
    pmc_id = item.get("PMC_id", "")

    prompt = f"""
你是一个医学病例时间线拆分助手。你的任务是把病例文本拆成“患者基础信息/特殊诉求 + 病史 + 后续按时间周期划分的诊疗阶段”。

只允许输出 JSON，不要输出任何解释、代码块或额外文字。

输出 schema 必须严格为：
{{
  "patient_overview": [
    "自然语言条目1",
    "自然语言条目2"
  ],
  "sections": [
    {{
      "stage": "病史",
      "time_label": "发病前/既往",
      "summary": "这一阶段的简短概括",
      "items": [
        {{
          "type": "病史",
          "title": "医生需要询问的关键词或内容",
          "content": "该项具体信息"
        }}
      ]
    }},
    {{
      "stage": "某个时间周期名称",
      "time_label": "初诊时/入院时/术后2周/复诊时等",
      "summary": "这一阶段的简短概括",
      "items": [
        {{
          "type": "主诉|问诊|检查结果|诊断|治疗",
          "title": "仅问诊/检查结果需要；主诉/诊断/治疗必须为 null",
          "content": "该项具体信息"
        }}
      ]
    }}
  ]
}}

规则：
1. 第一部分不是 section，而是 patient_overview。这里只放患者个人信息、人口学信息、特殊诉求、重要背景、主观偏好等，每条一项，用自然语言表达，不需要 title/type。
2. 第一个 section 必须是“病史”。病史包含既往症状、既往疾病、外院诊断、既往治疗、既往事件等。外院已有诊断也算病史。
3. 病史之后，按照时间顺序，把后续内容拆成多个 section。每个 section 表示一个相对独立的时间周期。
4. 每个 section 内部，把信息拆成尽可能原子化的 item。不同检查、不同诊断、不同治疗，必须拆成不同 item。
5. type 仅允许：主诉、问诊、检查结果、诊断、治疗、病史。
6. title 规则：
   - 病史：必须有 title，表示医生需要问患者的内容或关键词。
   - 问诊：必须有 title，表示医生需要询问的关键词。
   - 检查结果：必须有 title，表示医生需要开具的检查名。
   - 主诉、诊断、治疗：title 必须是 null。
7. “主诉”只表示患者本次前来就诊/处理的主要原因，不要把所有问诊内容都放进主诉。
8. “检查结果”中，content 写检查发现或结果；title 写检查名称。
9. “诊断”只写明确诊断结论；“治疗”只写治疗动作/方案。
10. 如果某一阶段没有明确时间词，也要根据叙事顺序和临床流程合理划分阶段。
11. 不要遗漏原文中对临床流程有用的重要信息，但也不要把整句原文机械复制为大块内容；应提炼成清晰条目。
12. 保持中文输出。

示意：
- patient_overview 可放：“67岁女性”“希望保肢”“既往无明显基础病”
- 病史 section 可放：“反复头痛”“外院诊断为疾病A”
- 后续阶段 item 可放：
  - 主诉：因左髋部肿块增大伴疼痛就诊
  - 问诊(title=跌倒史)：11个月前跌倒后出现髋部肿块
  - 检查结果(title=CT平扫)：未见移位性骨折，但提示左侧近端股骨周围软组织异常
  - 诊断：疾病B
  - 治疗：实施治疗C

PMC ID: {pmc_id}

病例全文：
{context}
""".strip()

    return [
        {
            "role": "system",
            "content": "你是一个严格遵守 JSON schema 的医学信息抽取助手。",
        },
        {"role": "user", "content": prompt},
    ]


def call_model_with_retry(
    client: OpenAI,
    model: str,
    messages: List[Dict[str, str]],
    max_retries: int = 2,
) -> Dict[str, Any]:
    local_messages = list(messages)
    last_error = ""

    for attempt in range(max_retries + 1):
        response = client.chat.completions.create(
            model=model,
            messages=local_messages,
            max_completion_tokens=30000,
        )
        text = response.choices[0].message.content or ""

        try:
            return parse_structured_output(text)
        except Exception as exc:
            last_error = f"{type(exc).__name__}: {exc}"
            if attempt < max_retries:
                local_messages = local_messages + [
                    {
                        "role": "user",
                        "content": (
                            "输出格式不合格。请只返回合法 JSON，并严格满足 schema。"
                            "第一段必须是 patient_overview；第一个 section 必须是病史；"
                            "问诊/检查结果/病史必须有 title；主诉/诊断/治疗的 title 必须为 null；"
                            f"上次错误：{last_error}"
                        ),
                    }
                ]

    raise ValueError(f"Failed to parse model output after retries: {last_error}")

